<template>
  <view class="container">
    <view class="tabs">
      <view 
        class="tab" 
        :class="{ active: activeTab === 'received' }" 
        @tap="switchTab('received')"
      >
        收到的邀请
      </view>
      <view 
        class="tab" 
        :class="{ active: activeTab === 'sent' }" 
        @tap="switchTab('sent')"
      >
        发出的邀请
      </view>
    </view>
    
    <view class="content">
      <!-- 收到的邀请 -->
      <view v-if="activeTab === 'received'" class="invitation-list">
        <view 
          v-for="invitation in receivedInvitations" 
          :key="invitation.id" 
          class="invitation-item"
        >
          <view class="invitation-info">
            <text class="from-user">来自用户 {{ invitation.fromUserId }}</text>
            <text class="time">{{ formatTime(invitation.createTime) }}</text>
          </view>
          <view class="invitation-status">
            <text :class="getStatusClass(invitation.status)">
              {{ getStatusText(invitation.status) }}
            </text>
          </view>
          <view class="invitation-actions" v-if="invitation.status === 0">
            <button class="accept-btn" @tap="acceptInvitation(invitation)">接受</button>
            <button class="reject-btn" @tap="rejectInvitation(invitation)">拒绝</button>
          </view>
        </view>
        <view v-if="receivedInvitations.length === 0" class="empty">
          暂无收到的邀请
        </view>
      </view>
      
      <!-- 发出的邀请 -->
      <view v-if="activeTab === 'sent'" class="invitation-list">
        <view 
          v-for="invitation in sentInvitations" 
          :key="invitation.id" 
          class="invitation-item"
        >
          <view class="invitation-info">
            <text class="to-user">发送给用户 {{ invitation.toUserId }}</text>
            <text class="time">{{ formatTime(invitation.createTime) }}</text>
          </view>
          <view class="invitation-status">
            <text :class="getStatusClass(invitation.status)">
              {{ getStatusText(invitation.status) }}
            </text>
          </view>
        </view>
        <view v-if="sentInvitations.length === 0" class="empty">
          暂无发出的邀请
        </view>
      </view>
    </view>
  </view>
</template>

<script>
import { apiGetReceivedInvitations, apiGetSentInvitations, apiAcceptInvite, apiRejectInvite } from '@/common/api.js';
import { getUserIdFromToken } from '@/common/auth.js';

export default {
  name: 'InvitationsPage',
  data() {
    return {
      activeTab: 'received',
      receivedInvitations: [],
      sentInvitations: []
    };
  },
  onLoad() {
    this.loadInvitations();
  },
  methods: {
    switchTab(tab) {
      this.activeTab = tab;
      this.loadInvitations();
    },
    
    async loadInvitations() {
      const userId = getUserIdFromToken();
      if (!userId) return;
      
      try {
        if (this.activeTab === 'received') {
          const response = await apiGetReceivedInvitations(userId);
          this.receivedInvitations = response || [];
        } else {
          const response = await apiGetSentInvitations(userId);
          this.sentInvitations = response || [];
        }
      } catch (error) {
        console.error('加载邀请列表失败:', error);
        uni.showToast({
          title: '加载失败',
          icon: 'none'
        });
      }
    },
    
    formatTime(time) {
      if (!time) return '';
      const date = new Date(time);
      return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')} ${String(date.getHours()).padStart(2, '0')}:${String(date.getMinutes()).padStart(2, '0')}`;
    },
    
    getStatusText(status) {
      switch (status) {
        case 0: return '待处理';
        case 1: return '已接受';
        case 2: return '已拒绝';
        default: return '未知';
      }
    },
    
    getStatusClass(status) {
      switch (status) {
        case 0: return 'status-pending';
        case 1: return 'status-accepted';
        case 2: return 'status-rejected';
        default: return '';
      }
    },
    
    async acceptInvitation(invitation) {
      const userId = getUserIdFromToken();
      if (!userId) return;
      
      try {
        await apiAcceptInvite({
          userId: userId,
          invitationId: invitation.fromUserId
        });
        
        uni.showToast({
          title: '已接受邀请',
          icon: 'success'
        });
        
        // 更新邀请状态
        invitation.status = 1;
      } catch (error) {
        console.error('接受邀请失败:', error);
        uni.showToast({
          title: '接受失败',
          icon: 'none'
        });
      }
    },
    
    async rejectInvitation(invitation) {
      const userId = getUserIdFromToken();
      if (!userId) return;
      
      try {
        await apiRejectInvite({
          userId: userId,
          invitationId: invitation.fromUserId
        });
        
        uni.showToast({
          title: '已拒绝邀请',
          icon: 'success'
        });
        
        // 更新邀请状态
        invitation.status = 2;
      } catch (error) {
        console.error('拒绝邀请失败:', error);
        uni.showToast({
          title: '拒绝失败',
          icon: 'none'
        });
      }
    }
  }
};
</script>

<style scoped>
.container {
  padding: 20rpx;
}

.tabs {
  display: flex;
  background: #f5f5f5;
  border-radius: 10rpx;
  margin-bottom: 30rpx;
}

.tab {
  flex: 1;
  text-align: center;
  padding: 20rpx;
  font-size: 28rpx;
  color: #666;
}

.tab.active {
  background: #007AFF;
  color: white;
  border-radius: 10rpx;
}

.invitation-list {
  min-height: 500rpx;
}

.invitation-item {
  background: white;
  border-radius: 10rpx;
  padding: 20rpx;
  margin-bottom: 20rpx;
  box-shadow: 0 2rpx 10rpx rgba(0,0,0,0.1);
}

.invitation-info {
  display: flex;
  justify-content: space-between;
  margin-bottom: 10rpx;
}

.from-user, .to-user {
  font-weight: bold;
  color: #333;
}

.time {
  color: #999;
  font-size: 24rpx;
}

.invitation-status {
  margin-bottom: 10rpx;
}

.status-pending {
  color: #FF9900;
}

.status-accepted {
  color: #07C160;
}

.status-rejected {
  color: #FA5151;
}

.invitation-actions {
  display: flex;
  justify-content: flex-end;
  gap: 20rpx;
}

.accept-btn {
  background: #07C160;
  color: white;
  border: none;
  padding: 10rpx 20rpx;
  border-radius: 5rpx;
  font-size: 24rpx;
}

.reject-btn {
  background: #FA5151;
  color: white;
  border: none;
  padding: 10rpx 20rpx;
  border-radius: 5rpx;
  font-size: 24rpx;
}

.empty {
  text-align: center;
  color: #999;
  padding: 50rpx 0;
}
</style>